# dual explorer-H1 · S35-T1-A-E2
def assess(record: dict) -> str:
    required = {"case_id", 'drops', 'metric', 'means_fraud'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if record["means_fraud"] is False else "REJECT_CAUSAL_CLAIM"

valid = {"case_id": "CASO-LIM-035-1A", **{'drops': {'shared_phone': 0.1, 'amount_7d': 0.03}, 'metric': 'precision_at_k', 'means_fraud': False}}
invalid = {"case_id": "CASO-LIM-035-1A", **{'drops': {'shared_phone': 0.1}, 'metric': 'precision_at_k', 'means_fraud': True}}
incomplete = {**valid}
incomplete.pop("drops")
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

# dual explorer-H1 · S35-T1-A-E3
def decide(record: dict) -> str:
    required = {'case_id', 'drops', 'metric', 'means_fraud'}
    missing = sorted(required - record.keys())
    if missing:
        return 'REQUEST_METRIC_DROP'
    return 'CONTINUE' if record.get('means_fraud') is False else 'REJECT_CAUSAL_CLAIM'
valid = {'case_id': 'CASO-LIM-035-1A', 'drops': {'shared_phone': 0.1}, 'metric': 'precision_at_k', 'means_fraud': False}
invalid = {**valid, 'means_fraud': True}
uncertain = {k: v for k, v in valid.items() if k != 'drops'}
results = [decide(item) for item in (valid, invalid, uncertain)]
print(*results)

